import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Loom","description":"Documentation for the Fabric Loom Gradle plugin.","frontmatter":{"title":"Loom","description":"Documentation for the Fabric Loom Gradle plugin.","authors":["Atakku","caoimhebyrne","Daomephsta","JamiesWhiteShirt","Juuxel","kb-1000","modmuss50","SolidBlock-cn"],"resources":{"https://github.com/fabricMC/fabric-loom":"Source Code for Fabric Loom"},"files":[]},"headers":[],"relativePath":"develop/loom/index.md","filePath":"develop/loom/index.md","lastUpdated":1774467289000}`);var a={name:`develop/loom/index.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Loom <a class="header-anchor" href="#h1" aria-label="Permalink to “Loom”">​</a></h1><p>Fabric Loom, or just Loom for short, is a <a href="https://gradle.org/" target="_blank" rel="noreferrer">Gradle</a> plugin for development of mods in the Fabric ecosystem.</p><p>Loom provides utilities to install Minecraft and mods in a development environment so that you can link against them with respect to Minecraft obfuscation and its differences between distributions and versions. It also provides run configurations for use with Fabric Loader, Mixin compile processing and utilities for Fabric Loader&#39;s jar-in-jar system.</p><p>Loom supports <em>all</em> versions of Minecraft, even those not officially supported by Fabric API, because it is version-independent.</p><div class="warning custom-block"><p class="custom-block-title">IMPORTANT</p><p>This page is a reference of all options and features of Loom. If you are just getting started, please read the <a href="./../">Introduction to Fabric</a>.</p></div><h2 id="plugin-ids" tabindex="-1">Plugin IDs <a class="header-anchor" href="#plugin-ids" aria-label="Permalink to “Plugin IDs”">​</a></h2><p>Loom uses multiple different plugin IDs:</p><ul><li><code>net.fabricmc.fabric-loom</code>, for non-obfuscated versions (Minecraft 26.1 or newer)</li><li><code>net.fabricmc.fabric-loom-remap</code>, for obfuscated versions (Minecraft 1.21.11 or older)</li><li><code>fabric-loom</code> (legacy), only supported for backwards compatibility with obfuscated versions. Use <code>net.fabricmc.fabric-loom-remap</code> instead</li><li><code>net.fabricmc.fabric-loom-companion</code>, in advanced multi-project setups. Read more about <a href="./classpath-groups#multi-project">Sub Projects</a></li></ul><h2 id="subprojects" tabindex="-1">Depending on Subprojects <a class="header-anchor" href="#subprojects" aria-label="Permalink to “Depending on Subprojects”">​</a></h2><p>While setting up a multi-project build that depends on another Loom project, you should use the <code>namedElements</code> configuration when depending on the other project. By default, a project&#39;s &quot;outputs&quot; are remapped to intermediary names. The <code>namedElements</code> configuration contains the project outputs that have not been remapped.</p><div class="language-groovy line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">groovy</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">dependencies {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> implementation project(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">path</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;:name&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">configuration</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;namedElements&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>If you are using split source sets in a multi-project build, you will also need to add a dependency for the other project&#39;s client source set.</p><div class="language-groovy line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">groovy</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">dependencies {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> clientImplementation project(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;:name&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sourceSets</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">client</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">output</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h2 id="split-sources" tabindex="-1">Split Client &amp; Common Code <a class="header-anchor" href="#split-sources" aria-label="Permalink to “Split Client &amp; Common Code”">​</a></h2><p>For years, a common source of server crashes had been mods accidentally calling client-only code when installed on a server. Newer Loom and Loader versions provide an option to require all client code to be moved into its own source set. This is to stop the problem at compile time, but the build will still result in a single jar file which works on either side.</p><p>The following snippet from a <code>build.gradle</code> file shows how you can enable this for your mod. As your mod will now be split across two source sets, you will need to use the new DSL to define your mod&#39;s source sets. This enables Fabric Loader to group your mod&#39;s classpath together. This is also useful for some other complex multi-project setups.</p><p>Minecraft 1.18 (1.19 recommended), Loader 0.14 and Loom 1.0 or later are required to split the client and common code.</p><div class="language-groovy line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">groovy</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">loom {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> splitEnvironmentSourceSets()</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> mods {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">   example</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">mod {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">     sourceSet sourceSets</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">main</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">     sourceSet sourceSets</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">client</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">   }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><h2 id="issues" tabindex="-1">Resolving Issues <a class="header-anchor" href="#issues" aria-label="Permalink to “Resolving Issues”">​</a></h2><p>Loom and/or Gradle can sometimes fail due to corrupted cache files. Running <code>./gradlew build --refresh-dependencies</code> will force Gradle and Loom to re-download and recreate all files. This may take a few minutes, but is usually enough to resolve cache-related issues.</p><h2 id="setup" tabindex="-1">Development Environment Setup <a class="header-anchor" href="#setup" aria-label="Permalink to “Development Environment Setup”">​</a></h2><p>Loom is designed to work out-of-the-box, by simply setting up a workspace in your IDE. It does quite a few things behind the scenes to create a development environment with Minecraft:</p><ul><li>Downloads the client and server jar from official channels for the configured version of Minecraft</li><li>Merges the client and server jar to produce a merged jar with <code>@Environment</code> and <code>@EnvironmentInterface</code> annotations</li><li>Downloads the configured mappings</li><li>Remaps the merged jar with intermediary mappings to produce an intermediary jar</li><li>Remaps the merged jar with Yarn mappings to produce a mapped jar</li><li>Optional: Decompiles the mapped jar to produce a mapped sources jar and linemap, and applies the linemap to the mapped jar</li><li>Adds Minecraft dependencies</li><li>Downloads Minecraft assets</li><li>Processes and includes mod-augmented dependencies</li></ul><h2 id="caches" tabindex="-1">Caches <a class="header-anchor" href="#caches" aria-label="Permalink to “Caches”">​</a></h2><ul><li><code>\${GRADLE_HOME}/caches/fabric-loom</code>: The user cache, a cache shared by all Loom projects for a user. Used to cache Minecraft assets, jars, merged jars, intermediary jars and mapped jars</li><li><code>.gradle/loom-cache</code>: The root project persistent cache, a cache shared by a project and its subprojects. Used to cache remapped mods, as well as generated included mod jars</li><li><code>**/build/loom-cache</code>: The (sub)projects&#39; build cache</li></ul><h2 id="configurations" tabindex="-1">Dependency Configurations <a class="header-anchor" href="#configurations" aria-label="Permalink to “Dependency Configurations”">​</a></h2><ul><li><code>minecraft</code>: Defines the version of Minecraft to be used in the development environment</li><li><code>mappings</code>: Defines the mappings to be used in the development environment</li><li><code>modImplementation</code>, <code>modApi</code> and <code>modRuntime</code>: Augmented variants of <code>implementation</code>, <code>api</code> and <code>runtime</code> for mod dependencies. Will be remapped to match the mappings in the development environment and has any nested jars removed</li><li><code>include</code>: Declares a dependency that should be included as a jar-in-jar in the final mod output. This dependency configuration is not transitive. For non-mod dependencies, Loom will generate a mod jar with a <code>fabric.mod.json</code> using the mod ID for the name, and the same version</li></ul><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Dependencies declared with <code>include</code> are added to <code>remapJar</code> in remapping Loom, or to <code>jar</code> in non-remapping Loom respectively. Because of this, jar tasks from other plugins (such as <code>shadowJar</code>) will not include these dependencies by default.</p></div><h2 id="configuration" tabindex="-1">Default Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to “Default Configuration”">​</a></h2><ul><li>Applies the following plugins: <code>java</code>, <code>eclipse</code></li><li>Adds the following Maven repositories: <a href="https://maven.fabricmc.net/" target="_blank" rel="noreferrer">Fabric</a>, <a href="https://libraries.minecraft.net/" target="_blank" rel="noreferrer">Mojang</a> and Maven Central</li><li>Configures the <code>eclipse</code> task to be finalized by the <code>genEclipseRuns</code> task</li><li>If an <code>.idea</code> folder exists in the root project, downloads assets (if not up-to-date) and installs run configurations in <code>.idea/runConfigurations</code></li><li>Adds <code>net.fabricmc:fabric-mixin-compile-extensions</code> and its dependencies with the <code>annotationProcessor</code> dependency configuration</li><li>Configures all non-test JavaCompile tasks with configurations for the Mixin annotation processor</li><li>Configures the <code>remapJar</code> task to output a JAR with the same name as the <code>jar</code> task output, then adds a &quot;dev&quot; classifier to the <code>jar</code> task</li><li>Configures the <code>remapSourcesJar</code> task to process the <code>sourcesJar</code> task output if the task exists</li><li>Adds the <code>remapJar</code> task and the <code>remapSourcesJar</code> task as dependencies of the <code>build</code> task</li><li>Configures the <code>remapJar</code> task and the <code>remapSourcesJar</code> task to add their outputs as <code>archives</code> artifacts when executed</li><li>For each MavenPublication (from the <code>maven-publish</code> plugin), manually appends dependencies to the POM for mod-augmented dependency configurations, provided the dependency configuration has a Maven scope</li></ul><p>All run configurations have the run directory <code>\${projectDir}/run</code> and the VM argument <code>-Dfabric.development=true</code>. The main classes for run configurations are usually defined by a <code>fabric-installer.json</code> file in the root of Fabric Loader&#39;s JAR file when it is included as a mod dependency, but the file can be defined by any mod dependency. If no such file is found, the main classes default to <code>net.fabricmc.loader.launch.knot.KnotClient</code> and <code>net.fabricmc.loader.launch.knot.KnotServer</code>.</p>`,31)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};